import java.util.Scanner;

class Solution {
    public static void main(String args[]) {
        Scanner in = new Scanner(System.in);

        int totalAllow = 0;
        // Read 7 daily allowances and calculate total
        for (int i = 0; i < 7; i++) {
            int allow = in.nextInt();

            totalAllow += allow;
        }

        int totalExp = 0;
        // Read 7 daily expenditures and calculate total
        for (int i = 0; i < 7; i++) {
            int exp = in.nextInt();

            totalExp += exp;
        }

        int WeeklySavings = totalAllow - totalExp;

        // Output results as specified
        System.out.println("Total Allowance: " + totalAllow);
        System.out.println("Total Expenses: " + totalExp);
        System.out.println("Weekly Savings: " + WeeklySavings);
    }
}
